    reject_rows = 0
    errors = []

    with open(output_file) as f:
        for line_no, line in enumerate(f, 1):
            try:
                row = json.loads(line)

                # Validate required fields by decision type
                if row["decision"] == "emit_edge":
                    required = {"decision", "candidate_kind", "evidence_kind", "source_slug", "target_slug", "edge_type", "evidence_snippet", "evidence_section", "confidence_tier"}
                    missing = required - set(row.keys())
                    if missing:
                        errors.append(f"Line {line_no}: emit_edge missing fields: {missing}")
                    emit_rows += 1

                    # Verify confidence_tier is int
                    if not isinstance(row.get("confidence_tier"), int):
                        errors.append(f"Line {line_no}: confidence_tier must be int, got {type(row.get('confidence_tier'))}")

                elif row["decision"] == "reject_just_mention":
                    required = {"decision", "candidate_kind", "source_slug", "target_slug", "reason"}
                    missing = required - set(row.keys())
                    if missing:
                        errors.append(f"Line {line_no}: reject_just_mention missing fields: {missing}")
                    reject_rows += 1

            except json.JSONDecodeError as e:
                errors.append(f"Line {line_no}: JSON parse error: {e}")

    basename = Path(output_file).name
    if errors:
        print(f"✗ {basename}: {len(errors)} errors")
        for err in errors[:3]:
            print(f"    {err}")
    else:
        print(f"✓ {basename}: {emit_rows} emit_edge, {reject_rows} reject_just_mention (valid)")

